def token_f1(a,b):
    atoks = a.split()
    btoks = b.split()
    a_count = {}
    b_count = {}
    for t in atoks:
        a_count[t] = a_count.get(t,0)+1
    for t in btoks:
        b_count[t] = b_count.get(t,0)+1
    overlap = 0
    for t, ct in a_count.items():
        overlap += min(ct, b_count.get(t,0))
    prec = overlap/len(atoks) if atoks else 0
    rec = overlap/len(btoks) if btoks else 0
    f1 = 2*prec*rec/(prec+rec) if (prec+rec)>0 else 0
    return prec, rec, f1, overlap, len(atoks), len(btoks)

